long long solve(std::vector<long long> nums) {
    if (nums.empty()) {
        return 0;
    }

    // The operation allows replacing nums[a] with nums[b] if nums[a] % nums[b] == 0.
    // To minimize the sum, we want to replace larger numbers with smaller divisors.
    // The smallest possible value any element can take must be a divisor of its original value.
    // Since we can repeatedly apply this operation, the minimum achievable value for any element
    // is the greatest common divisor (GCD) of all the initial numbers.
    // If G = GCD(nums[0], ..., nums[n-1]), then G divides every nums[i].
    // While G might not be initially present, the structure of the operation allows all numbers
    // to be reduced to G if G is the GCD. This is a known property for this type of reduction problem.

    long long resultGcd = nums[0];
    for (size_t i = 1; i < nums.size(); ++i) {
        resultGcd = gcd(resultGcd, nums[i]);
    }

    // The minimum sum is achieved when every element is replaced by the GCD of the original array.
    long long min_sum = (long long)nums.size() * resultGcd;

    return min_sum;
}

